import{_ as a,o as e,c as t,ai as i}from"./chunks/framework.BZ-K7CQ_.js";const k=JSON.parse('{"title":"Live-Image Proxy","description":"","frontmatter":{"sidebar":true},"headers":[],"relativePath":"webcam.md","filePath":"webcam.md"}'),n={name:"webcam.md"};function l(o,s,h,r,d,c){return e(),t("div",null,[...s[0]||(s[0]=[i(`<h1 id="live-image-proxy" tabindex="-1">Live-Image Proxy <a class="header-anchor" href="#live-image-proxy" aria-label="Permalink to “Live-Image Proxy”">​</a></h1><p>The Arcsecond CLI ships a native live-image proxy that lets <a href="https://www.arcsecond.io" target="_blank" rel="noreferrer">Arcsecond.local</a> — the self-hosted version of Arcsecond — access <strong>USB webcams</strong> and <strong>all-sky cameras</strong> attached to (or visible from) the host machine.</p><p>Docker Desktop on Windows and macOS does not forward USB devices into containers, and may not have access to host filesystem paths where all-sky software writes its images. The proxy solves both: it runs natively on the host, where it has direct USB access and can read local files, and exposes the feeds over HTTP and WebSocket. The Arcsecond backend container reaches the proxy via <code>host.docker.internal</code>.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to “Installation”">​</a></h2><p>The proxy requires extra dependencies (OpenCV and aiohttp) that are not installed by default. Install them with the <code>webcam</code> extra:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> arcsecond[webcam]</span></span></code></pre></div><p>The extra is named <code>webcam</code> for backward compatibility, but it covers all-sky support too.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>If your shell treats square brackets specially (e.g. zsh), quote the package name:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pip</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;arcsecond[webcam]&#39;</span></span></code></pre></div></div><div class="warning custom-block"><p class="custom-block-title">Windows users — use PowerShell, not WSL</p><p>On Windows, the Arcsecond CLI <strong>must be installed and run natively using PowerShell</strong> (or the standard Windows Command Prompt). Do <strong>not</strong> use the Bash shell that comes with WSL (Windows Subsystem for Linux).</p><p>WSL runs in a virtualised Linux environment that does not have direct access to the host&#39;s USB devices. As a result, the webcam proxy cannot see cameras attached to the Windows machine when launched from inside WSL.</p></div><h2 id="usb-webcams" tabindex="-1">USB webcams <a class="header-anchor" href="#usb-webcams" aria-label="Permalink to “USB webcams”">​</a></h2><h3 id="detecting" tabindex="-1">Detecting <a class="header-anchor" href="#detecting" aria-label="Permalink to “Detecting”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arcsecond</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> webcam</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> detect</span></span></code></pre></div><p>This probes device indices 0 through 9 and prints the resolution and frame rate of each camera found.</p><h3 id="starting-the-proxy" tabindex="-1">Starting the proxy <a class="header-anchor" href="#starting-the-proxy" aria-label="Permalink to “Starting the proxy”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arcsecond</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> webcam</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--port </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">8765]</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--host </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0.0.0.0]</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [--log-level </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">INFO]</span></span></code></pre></div><h2 id="all-sky-cameras" tabindex="-1">All-sky cameras <a class="header-anchor" href="#all-sky-cameras" aria-label="Permalink to “All-sky cameras”">​</a></h2><p>The proxy supports all-sky cameras whose driver software writes JPEG images to disk. The two most common stacks are auto-discovered:</p><ul><li><strong>Thomas Jacquin&#39;s allsky</strong> (<a href="https://github.com/AllskyTeam/allsky" target="_blank" rel="noreferrer">github.com/AllskyTeam/allsky</a>), typically on a Raspberry Pi</li><li><strong>indi-allsky</strong> (<a href="https://github.com/aaronwmorris/indi-allsky" target="_blank" rel="noreferrer">github.com/aaronwmorris/indi-allsky</a>), INDI-based</li></ul><h3 id="detecting-1" tabindex="-1">Detecting <a class="header-anchor" href="#detecting-1" aria-label="Permalink to “Detecting”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arcsecond</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> allsky</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> detect</span></span></code></pre></div><p>This checks well-known paths:</p><table tabindex="0"><thead><tr><th>Path</th><th>Software</th></tr></thead><tbody><tr><td><code>~/allsky/tmp/image.jpg</code></td><td>Jacquin allsky</td></tr><tr><td><code>/var/www/html/allsky/current/tmp/image.jpg</code></td><td>Jacquin allsky</td></tr><tr><td><code>/var/lib/indi-allsky/images/latest.jpg</code></td><td>indi-allsky</td></tr><tr><td><code>~/indi-allsky/latest.jpg</code></td><td>indi-allsky</td></tr></tbody></table><h3 id="starting-with-custom-paths" tabindex="-1">Starting with custom paths <a class="header-anchor" href="#starting-with-custom-paths" aria-label="Permalink to “Starting with custom paths”">​</a></h3><p>If your software writes JPEGs to a non-standard location, register them explicitly. <code>--allsky</code> is repeatable; the value can be a file path or a glob (newest mtime wins):</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">arcsecond</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> allsky</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --allsky</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> roof=/srv/allsky/latest.jpg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --allsky</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> garden=&#39;/var/data/allsky/*.jpg&#39;</span></span></code></pre></div><p><code>arcsecond webcam start</code> accepts the same <code>--allsky</code> flag — both commands launch the same proxy.</p><h2 id="endpoints" tabindex="-1">Endpoints <a class="header-anchor" href="#endpoints" aria-label="Permalink to “Endpoints”">​</a></h2><p>The proxy exposes three endpoints:</p><table tabindex="0"><thead><tr><th>Endpoint</th><th>Method</th><th>Description</th></tr></thead><tbody><tr><td><code>/health</code></td><td>GET</td><td>Liveness check (<code>{&quot;status&quot;: &quot;ok&quot;}</code>)</td></tr><tr><td><code>/detect</code></td><td>GET</td><td>JSON list of available sources (webcam + allsky)</td></tr><tr><td><code>/stream/{id}</code></td><td>WebSocket</td><td>Continuous JPEG frame stream</td></tr></tbody></table><p>Source ids look like <code>webcam:0</code> or <code>allsky:roof</code>. Bare numeric ids (<code>/stream/0</code>) are accepted for backward compatibility and treated as <code>webcam:N</code>.</p><p>Press <code>Ctrl-C</code> to stop the proxy.</p><h2 id="connecting-arcsecond-local" tabindex="-1">Connecting Arcsecond.local <a class="header-anchor" href="#connecting-arcsecond-local" aria-label="Permalink to “Connecting Arcsecond.local”">​</a></h2><p>No extra configuration is needed when the proxy runs on the same machine as Arcsecond.local. The backend defaults to <code>http://host.docker.internal:8765</code>, so it can reach the proxy out of the box.</p><p>The typical workflow is:</p><ol><li>Start the proxy on the host: <code>arcsecond webcam start</code> (or <code>arcsecond allsky start</code>)</li><li>Start Arcsecond.local: <code>docker compose up -d</code></li><li>The backend automatically detects and streams from the host sources.</li></ol><h3 id="remote-proxy" tabindex="-1">Remote proxy <a class="header-anchor" href="#remote-proxy" aria-label="Permalink to “Remote proxy”">​</a></h3><p>If the cameras are attached to a different machine on the same network (e.g. a dome PC), start the proxy there and set <code>LIVE_IMAGE_PROXY_URL</code> in the <code>.env</code> file used by <code>docker-compose.yml</code>:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>LIVE_IMAGE_PROXY_URL=http://192.168.1.42:8765</span></span></code></pre></div><p>Replace <code>192.168.1.42</code> with the actual IP address or hostname. When this variable is not set, the backend falls back to <code>http://host.docker.internal:8765</code> (the Docker way of saying <code>http://localhost:8765</code> from within a container).</p><p>The previous variable name <code>WEBCAM_PROXY_URL</code> is still accepted as a deprecated fallback.</p><h2 id="stream-protocol" tabindex="-1">Stream protocol <a class="header-anchor" href="#stream-protocol" aria-label="Permalink to “Stream protocol”">​</a></h2><p>Each frame is sent as a JSON message over the WebSocket connection:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;frame&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;format&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;jpeg/base64&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;data&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;base64-encoded JPEG&gt;&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>For webcams, frames arrive at ~10 fps. For all-sky sources, a frame is sent only when the source file&#39;s mtime changes — typically every 30–120 seconds, depending on the camera&#39;s exposure cadence.</p><p>If the source becomes unavailable (device unplugged, file removed) the proxy sends an error message before closing the connection:</p><div class="language-json"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;message&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Cannot open webcam at device index 0.&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div>`,46)])])}const g=a(n,[["render",l]]);export{k as __pageData,g as default};
